Para simular las consultas, eh creado la funcion heavyFunction.... Aqui os pongo mi cÃ³digo. Â¿QuÃ© creeis que puede estar pasando? Lo curioso es que si os fijais en la consola, si que funciona bien.

library(future)
library(promises)
plan(multiprocess)

heavyFunction <- function(n){
  Sys.sleep(n)
  print(n)
}


ui <- fluidPage(
  actionButton("go","Show the data"),
  textOutput("result0sec"),
  textOutput("result10sec")

)

server <- function(input,output,session){


  data0 <- eventReactive(input$go,{
    heavyFunction(0)


  })

  data10 <- eventReactive(input$go,{
    future(heavyFunction(10))


  })
  output$result0sec <- renderText({
    data <- data0()
    print(data)
  })


  output$result10sec <- renderText({
    data <- data10()
    data%...>%print()
  })




}
shinyApp(ui,server)

